    const imageBuffer = Buffer.from(base64Data, 'base64');

    // 1. ИИ Анализ + Контент (Universal Beauty DNA)
    const aiResult = await analyzeAndGenerate(imageBuffer as any);

    // 2. Интеллектуальная подготовка (AI Seed for v53 Outpainting)
    let finalBaseBuffer: Buffer = imageBuffer;
    try {
      console.log(`[Dashboard] Creating AI_SEED for professional outpainting...`);
      const aiSeed = await generateSocialPost(imageBuffer, {
        format: 'AI_SEED',
        skipOverlay: true, // ✅ Don't put overlays on the seed!
        businessName: businessName || 'Beauty Expert',
        theme: 'ORIGINAL_CLEAN'
      });

      console.log(`[Dashboard] ATTEMPTING IMAGE ENHANCEMENT with ${CONFIG.MODELS.ENHANCEMENT}...`);
      finalBaseBuffer = await enhanceImage(aiSeed, aiResult.imagenPrompt);
    } catch (err) {
      console.error('IMAGE ENHANCEMENT FAILED (Quota or Timeout):', err);
      // Fallback: keep original if AI fails
    }

    // 3. Маппинг формата
    let socialFormat: SocialFormat = 'INSTAGRAM_POST';
    if (format === 'WhatsApp') socialFormat = 'STORY_9_16';
    if (format === 'Facebook') socialFormat = 'SQUARE_1_1';
    if (format === 'Telegram') socialFormat = 'ORIGINAL';

    // 4. Графический дизайн (Napi-Canvas Engine)
    const designedBuffer = await generateSocialPost(finalBaseBuffer, {
      format: socialFormat,
      businessName: businessName || 'Beauty Expert',
      overlay: aiResult.overlay,
      theme: 'ORIGINAL_CLEAN' 
    });

    // 5. Результат (v34 Stability Fix)
    return res.status(200).json({
      enhancedImage: `data:image/jpeg;base64,${designedBuffer.toString('base64')}`,
      post: aiResult.post,
      cta: aiResult.cta,
      service: aiResult.detectedService,
      ai_report: `דיזיין מוכן עבור ${format}. מערכת יציבה v34.`
    });

  } catch (error: any) {
    console.error('Unified Generation Error:', error);
    return res.status(500).json({ 
      error: error.message || 'Generation failed',
      details: error.response?.data || 'No detailed data',
      model: CONFIG.MODELS.ANALYSIS 
    });
  }
}

import { VercelRequest, VercelResponse } from '@vercel/node';
import { Telegraf } from 'telegraf';
import { analyzeAndGenerate, enhanceImage } from './_lib/content-engine.js';
import { getSupabase } from './_lib/supabase.js';

export default async function handler(req: VercelRequest, res: VercelResponse) {
  if (req.method !== 'POST') return res.status(405).send('Method Not Allowed');

  const { verifyQStashSignature } = await import('./_lib/security.js');
  const isAuthorized = await verifyQStashSignature(req);
  if (!isAuthorized) {
    return res.status(401).json({ error: 'Unauthorized: Invalid QStash Signature' });
  }

  const { chatId, formatType } = req.body;
  const bot = new Telegraf(process.env.TELEGRAM_BOT_TOKEN || '');

  console.log(`[Render-Worker v51.3] Starting Background Task: ${formatType} for chat: ${chatId}`);

  try {
    const supabase = getSupabase();
    if (!supabase) throw new Error('Supabase integration missing');

    const { data: session, error: sessErr } = await supabase
      .from('bot_sessions')
      .select('*')
      .eq('user_id', chatId)
      .single();

    if (sessErr || !session?.session_data?.originalBuffer) {
      await bot.telegram.sendMessage(chatId, '❌ מצטערים, המידע על התמונה אבד. אנא שלחו תמונה חדשה.');
      return res.status(404).send('Session not found');
    }

    const { generateSocialPost } = await import('./_lib/graphic-engine.js');
    let enhancedMaster: Buffer;
    let imagenPrompt = 'Luxury Beauty Design';

    // 🚀 TARGET FORMAT DETERMINATION (v53.0)
    let socialFormat: any = 'SQUARE_1_1';
    let formatName = 'Facebook (1:1)';
    
    if (formatType === 'INST') { socialFormat = 'INSTAGRAM_POST'; formatName = 'Instagram (4:5)'; }
    if (formatType === 'WATS') { socialFormat = 'STORY_9_16'; formatName = 'WhatsApp/Story (9:16)'; }
    if (formatType === 'FACE') { socialFormat = 'SQUARE_1_1'; formatName = 'Facebook (1:1)'; }

    // 🎨 FINAL SOCIAL RENDER (Formatting Only)
    console.log(`[Render-Worker] Target Format: ${formatName}`);

    // 🏆 CONSISTENCY SYSTEM (v52.2): Check for cached Master-File
    if (session.session_data.enhancedMaster) {
      console.log('[Render-Worker v52.2] Cache HIT: Using existing Master-File');
      enhancedMaster = Buffer.from(session.session_data.enhancedMaster, 'base64');
    } else {
      console.log('[Render-Worker v52.2] Cache MISS: Creating new Master-File');
      const originalBuffer = Buffer.from(session.session_data.originalBuffer, 'base64');

      // 1. Create AI Seed (Framed with context for Outpainting)
      console.log('[Render-Worker] Creating AI Seed (v53.0 Framed Canvas)...');
      const aiSeed = await generateSocialPost(originalBuffer, {
        format: socialFormat, 
        skipOverlay: true, // ✅ Don't put overlays on the seed!
        theme: 'ORIGINAL_CLEAN'
      });

      // 2. AI Analysis & Multi-Modal Expansion Generation (v52.8)
      console.log('[Render-Worker] Running Gemini 3.1 Pro Outpainting Analysis...');
      const uiPromptAddon = (session.session_data.lastOverlay || []).length > 0
        ? ` IMPORTANT: This image has price/title design. Integrate it as premium studio graphics. 
           SHARPEN THE TEXT OVERLAYS.`
        : '';
      
      const expansionPrompt = `
        PRO-LEVEL BEAUTY RETOUCH & STUDIO EXPANSION (v65.1 Art-Director Edition).
        1. MASTER POLISH: Locate the subject (nails, skin, face). Perform high-end retouching, remove imperfections, even out skin tone.
        2. SEAMLESS EXPANSION: The input image is a sharp subject inside a "Blurred Frame" context (instead of black). Use these colors and textures as a guide to EXPAND the scene into a full, seamless luxury beauty studio.
        3. FLAWLESS INTEGRATION: Ensure the transition between the original photo and the new background is invisible. No visible borders or lighting shifts.
        4. LUXURY STUDIO: Include high-end studio elements (marble, soft bokeh, professional lighting accessories).
        Style: Commercial Luxury Photography, Cinematic Lighting.
        ${uiPromptAddon}
      `;

      const aiResult = await analyzeAndGenerate(aiSeed, expansionPrompt);
      imagenPrompt = aiResult.imagenPrompt;

      // 3. High-Fidelity Outpainting (NANO BANANA PRO v53)
      console.log('[Render-Worker] Running NANO BANANA PRO Outpainting on Seed...');
      enhancedMaster = await enhanceImage(aiSeed, imagenPrompt);

      // 4. Persistence
      await supabase.from('bot_sessions').update({
        session_data: {
          ...session.session_data,
          enhancedMaster: enhancedMaster.toString('base64'),
          lastImagenPrompt: imagenPrompt,
          lastPost: aiResult.post,
          lastDesign: aiResult.design,
          lastStyle: aiResult.style
        }
      }).eq('user_id', chatId);
      
      session.session_data.lastPost = aiResult.post;
      session.session_data.lastDesign = aiResult.design;
      session.session_data.lastStyle = aiResult.style;
    }

    // 🎨 FINAL RENDER (POST-PROCESS DESIGN - v60 Art-Director Edition)
    const activeDesign = session.session_data.lastDesign || {};
    const activeStyle = session.session_data.lastStyle || { preset: 'GLASSMorphism', primaryColor: '#FFFFFF' };
    
    // 🏢 DYNAMIC BRANDING (v63.1)
    const { data: userData } = await supabase.from('users')
      .select('business_name')
      .eq('telegram_id', Number(chatId))
      .single();
    const realBusinessName = userData?.business_name || 'Beauty Expert';

    // 🚀 PRO COMPOSITION ENGINE v63.1 (Adaptive Safe Zones)
    const rawOverlays = session.session_data.lastOverlay || [];
    
    // Grouping strategy: Combine lines of the same type into one multiline box
    const groupedMap = new Map<string, any>();
    rawOverlays.forEach((line: any) => {
      const cleanText = (line.text || '').replace(/[✨\*]/g, '').trim();
      if (!cleanText) return;
      
      if (groupedMap.has(line.type)) {
        groupedMap.get(line.type).text += '\n' + cleanText;
      } else {
        groupedMap.set(line.type, { ...line, text: cleanText });
      }
    });

    // 🚀 PERFECT STACKING v61 (Collision-Weighted Composition)
    const usedPositions: { x: number, y: number, h: number }[] = [];
    const overlays = Array.from(groupedMap.values()).map((line: any) => {
      const design = activeDesign[line.type];
      
      // 📐 ADAPTIVE SAFE ZONES (v61/v65.1)
      let x = design?.x ?? (line.type === 'PRICE' ? 0.9 : (line.type === 'LOGO' ? 0.05 : 0.5));
      let y = design?.y;
      let align: 'left' | 'center' | 'right' = design?.align ?? (line.type === 'PRICE' ? 'right' : (line.type === 'LOGO' ? 'left' : 'center'));

      // Default Y-Slots for v61
      if (y === undefined) {
        if (line.type === 'TITLE') y = 0.12;
        else if (line.type === 'PRICE') y = 0.18; // Stagger price below title by default
        else if (line.type === 'PROMO') y = 0.82;
        else if (line.type === 'LOGO') { y = 0.94; x = 0.05; align = 'left'; }
        else y = 0.88;
      }

      // 🛑 PRECISION COLLISION AVOIDANCE (v61)
      const step = 0.12; 
      const thresholdY = 0.10; // Tighter vertical packing
      let attempts = 0;
      
      while (usedPositions.some(p => Math.abs(p.y - y!) < thresholdY && Math.abs(p.x - x) < 0.4) && attempts < 5) {
        // Intelligent Push: Push Title/Price UP, Push Promo/Logo DOWN
        if (y! < 0.4) y! -= step; 
        else y! += step;
        attempts++;
      }
      
      // Safe bounds (v61 Hard-Limit)
      y = Math.max(0.06, Math.min(0.94, y!));
      
      usedPositions.push({ x, y, h: step });

      // 🎨 LUXURY STYLE
      let fontSize = line.fontSize || 60;
      if (line.type === 'PROMO') fontSize = 72;
      if (line.type === 'LOGO') fontSize = 36;

      return { 
        ...line, 
        fontSize,
        xPosition: x, 
        yPosition: y, 
        textAlign: align,
        rotation: (line.type === 'PRICE' ? -3 : (line.type === 'PROMO' ? 2 : 0))
      };
    });

    const finalResult = await generateSocialPost(enhancedMaster, {
      format: socialFormat,
      businessName: realBusinessName,
      overlay: overlays, 
      style: activeStyle,
      theme: 'ORIGINAL_CLEAN'
    });

    const captionText = session.session_data.lastPost || 'התוצאה מוכנה!';
    const shareUrl = `https://wa.me/?text=${encodeURIComponent(captionText)}`;

    // 🚀 SHARE BUTTONS (v52.7)
    const shareButtons = [
      [
        { text: '📲 פרסם בסטטוס ווטסאפ', url: shareUrl },
        { text: '📸 פתח אינסטגרם', url: `https://www.instagram.com/` }
      ]
    ];

    // 🚀 5. FINAL SEND (Professional Clean Caption & Share UI)
    await bot.telegram.sendPhoto(chatId, { source: finalResult }, {
      caption: captionText,
      parse_mode: 'Markdown',
      reply_markup: { inline_keyboard: shareButtons }
    });

    console.log('[Render-Worker v52.7] Success Complete with Deep-Link Buttons');
    return res.status(200).send('Render Complete');

  } catch (err: any) {
    console.error('[Render-Worker Error]:', err);
    await bot.telegram.sendMessage(chatId, `❌ **שגיאת מערכת:** ${err.message}`).catch(() => {});
    return res.status(500).send(err.message);
  }
}

import { VercelRequest, VercelResponse } from '@vercel/node';
import { getSupabase } from './_lib/supabase.js';
import { scheduleNotification } from './_lib/qstash.js';
import { Telegraf } from 'telegraf';
import { validateTelegramWebAppData, getUserFromInitData } from './_lib/telegram-auth.js';

/**
 * Unified services endpoint — combines analytics, payments, webhooks.
 * Route by query param ?action=<action_name>
 * 
 * Actions: reminder, create-booking, approve-booking, reject-booking, cancel-booking
 */
export default async function handler(req: VercelRequest, res: VercelResponse) {
  const action = req.query.action as string;
  const supabase = getSupabase();
  if (!supabase) return res.status(500).send('Supabase connection failed');

  // --- Security Middleware (Telegram Auth) ---
  // Определяем, какие action требуют валидации TG Hash.
  const secureActions = ['create-booking', 'update-booking', 'approve-booking', 'reject-booking', 'cancel-booking'];
  
  let authUser: any = null;

  if (secureActions.includes(action)) {
    const initData = req.headers['x-telegram-init-data'] as string;
    const botToken = process.env.TELEGRAM_BOT_TOKEN;
    
    const isDev = process.env.NODE_ENV === 'development';
    const isValid = isDev || validateTelegramWebAppData(initData, botToken);
    
    if (!isValid) {
      return res.status(401).json({ error: 'Unauthorized: Invalid Telegram Signature (API Security Block)' });
    }
    
    authUser = getUserFromInitData(initData);
    if (!authUser?.id) {
      return res.status(401).json({ error: 'Unauthorized: User data missing' });
    }
  }

  switch (action) {



    // --- Reminder Webhook ---
    case 'reminder': {
      if (req.method !== 'POST') return res.status(405).send('Method Not Allowed');
      
      const { verifyQStashSignature } = await import('./_lib/security.js');
      const isQAuthorized = await verifyQStashSignature(req);
      if (!isQAuthorized) {
        return res.status(401).json({ error: 'Unauthorized: Invalid QStash Signature (Security Block)' });
      }

      const { bookingId, type } = req.body;
      if (!bookingId) return res.status(400).send('Missing bookingId');

      const bot = new Telegraf(process.env.TELEGRAM_BOT_TOKEN || '');
      const { data: booking, error } = await supabase
        .from('bookings')
        .select('*, master:master_id (telegram_id, business_name, full_name), client:client_id (telegram_id, full_name)')
        .eq('id', bookingId).single();
      
      if (error || !booking) return res.status(404).send('Booking not found');
      
      const timeStr = new Date(booking.start_time).toLocaleString('he-IL', { hour: '2-digit', minute: '2-digit', day: '2-digit', month: '2-digit' });
      const pre = type === '24h' ? '📢 תזכורת: מחר' : '⏰ תזכורת: בעוד 3 שעות';
      
      const clientMsg = `${pre} יש לך תור ב-${booking.master.business_name || booking.master.full_name}!\n🕓 שעה: ${timeStr}\nמחכים לך! ✨`;
      const masterMsg = `${pre} מגיע/ה אליך ${booking.client.full_name || 'לקוח/ה'}.\n🕓 שעה: ${timeStr}\nהכן/י את מקום העבודה! 💇‍♀️`;
      
      try {
        await Promise.all([
          bot.telegram.sendMessage(booking.master.telegram_id, clientMsg),
          bot.telegram.sendMessage(booking.client.telegram_id, masterMsg)
        ]);
        const updateField = type === '24h' ? { notified_24h: true } : { notified_3h: true };
        await supabase.from('bookings').update(updateField).eq('id', bookingId);
        return res.status(200).json({ success: true });
      } catch (err) {
        return res.status(500).send('Error sending messages');
      }
    }

    // --- [DIAGNOSTIC MODE v37] ---
    case 'diagnostic': {
      const results: any = { timestamp: new Date().toISOString(), tests: {} };
      try {
        const { analyzeAndGenerate } = await import('./_lib/content-engine.js');
        const testBuffer = Buffer.from('iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mP8/5+hHgAHggJ/PchI7wAAAABJRU5ErkJggg==', 'base64');
        await analyzeAndGenerate(testBuffer, 'diagnostic-test');
        results.tests.gemini_api = { status: 'PASSED' };
      } catch (e: any) {
        results.tests.gemini_api = { status: 'FAILED', error: e.message };
      }
      return res.status(200).json(results);
    }

    case 'create-booking': {
      if (req.method !== 'POST') return res.status(405).send('Method Not Allowed');
      const { masterTelegramId, clientTelegramId, serviceId, startTime, endTime } = req.body;
      const mId = Number(masterTelegramId);
      const cId = Number(clientTelegramId);
      if (!mId || !cId) return res.status(400).send('Missing valid IDs');

      // Security Check: You can only book for yourself (or you are admin, but let's stick to strict validation)
      if (authUser && Number(authUser.id) !== cId && process.env.NODE_ENV !== 'development') {
          return res.status(403).json({ error: 'Forbidden: Cannot create booking for another user' });
      }

      try {
        const { data: mUser } = await supabase.from('users').select('id, business_name, full_name, telegram_id').eq('telegram_id', mId).single();
        const { data: cUser } = await supabase.from('users').select('id, full_name, telegram_id').eq('telegram_id', cId).single();
        
        if (!mUser || !cUser) return res.status(404).json({ error: 'Master or Client not found in DB' });

        // Если передана услуга, получаем её цену и длительность
        let duration = 60;
        let price = 0;
        if (serviceId) {
          const { data: svc } = await supabase.from('services').select('price, duration_mins').eq('id', serviceId).single();
          if (svc) {
            price = Number(svc.price);
            duration = Number(svc.duration_mins);
          }
        }

        const calculatedEndTime = new Date(new Date(startTime).getTime() + duration * 60 * 1000).toISOString();

        const { data: booking, error: bErr } = await supabase
          .from('bookings')
          .insert({
            master_id: mUser.id,
            client_id: cUser.id,
            service_id: serviceId || null,
            total_price: price || null,
            start_time: startTime,
            end_time: endTime || calculatedEndTime,
            status: 'pending'
          })
          .select()
          .single();

        if (bErr) throw bErr;

        const bot = new Telegraf(process.env.TELEGRAM_BOT_TOKEN || '');
        const timeStr = new Date(startTime).toLocaleString('he-IL', { hour: '2-digit', minute: '2-digit', day: '2-digit', month: '2-digit' });
        
        const masterMsg = `🔔 **בקשת תור חדשה!**\n👤 לקוח: ${cUser.full_name}\n🕓 שעה: ${timeStr}\n\nהיכנסי ל-Studio כדי לאשר או לדחות את התור. ✨`;
        const clientMsg = `⏳ **בקשתך נשלחה!**\n📍 עסק: ${mUser.business_name || mUser.full_name}\n🕓 שעה: ${timeStr}\n\nאנחנו מחכים לאישור המאסטר. נעדכן אותך מיד כשיתקבל אישור! 🙏`;

        await Promise.all([
          bot.telegram.sendMessage(masterTelegramId, masterMsg, { parse_mode: 'Markdown' }),
          bot.telegram.sendMessage(clientTelegramId, clientMsg, { parse_mode: 'Markdown' })
        ]);

        return res.status(200).json({ success: true, bookingId: booking.id });
      } catch (err: any) {
        console.error('BOOKING ERROR:', err);
        return res.status(500).json({ error: err.message });
      }
    }

    // --- Approve Booking ---
    case 'approve-booking': {
      if (req.method !== 'POST') return res.status(405).send('Method Not Allowed');
      const { bookingId } = req.body;
      if (!bookingId) return res.status(400).send('Missing bookingId');

      try {
        const { data: booking, error: bErr } = await supabase
          .from('bookings')
          .update({ status: 'confirmed' })
          .eq('id', bookingId)
          .select('*, master:master_id (telegram_id, business_name, full_name), client:client_id (telegram_id, full_name)')
          .single();

        if (bErr || !booking) return res.status(404).send('Booking not found');

        const bot = new Telegraf(process.env.TELEGRAM_BOT_TOKEN || '');
        const timeStr = new Date(booking.start_time).toLocaleString('he-IL', { hour: '2-digit', minute: '2-digit', day: '2-digit', month: '2-digit' });
        
        const clientMsg = `✅ **יש! התור שלך אושר!**\n📍 עסק: ${booking.master.business_name || booking.master.full_name}\n🕓 שעה: ${timeStr}\n\nנתראה בקרוב! ✨`;
        await bot.telegram.sendMessage(booking.client.telegram_id, clientMsg, { parse_mode: 'Markdown' });

        // Schedule QStash Reminders
        const now = new Date().getTime();
        const start = new Date(booking.start_time).getTime();
        
        const delay24h = (start - (24 * 60 * 60 * 1000) - now) / 1000;
        if (delay24h > 0) await scheduleNotification(Math.floor(delay24h), '24h', booking.id);

        const delay3h = (start - (3 * 60 * 60 * 1000) - now) / 1000;
        if (delay3h > 0) await scheduleNotification(Math.floor(delay3h), '3h', booking.id);

        return res.status(200).json({ success: true });
      } catch (err: any) {
        return res.status(500).json({ error: err.message });
      }
    }

    // --- Reject Booking ---
    case 'reject-booking': {
      if (req.method !== 'POST') return res.status(405).send('Method Not Allowed');
      const { bookingId } = req.body;
      if (!bookingId) return res.status(400).send('Missing bookingId');

      try {
        const { data: booking, error: bErr } = await supabase
          .from('bookings')
          .update({ status: 'rejected' })
          .eq('id', bookingId)
          .select('*, master:master_id (telegram_id, business_name, full_name), client:client_id (telegram_id, full_name)')
          .single();

        if (bErr || !booking) return res.status(404).send('Booking not found');

        const bot = new Telegraf(process.env.TELEGRAM_BOT_TOKEN || '');
        const timeStr = new Date(booking.start_time).toLocaleString('he-IL', { hour: '2-digit', minute: '2-digit', day: '2-digit', month: '2-digit' });
        
        const clientMsg = `😔 **מצטערים, התור לא אושר...**\n📍 עסק: ${booking.master.business_name || booking.master.full_name}\n🕓 שעה: ${timeStr}\n\nהמאסטר לא פנוי במועד זה. נשמח אם תבחרי מועד אחר ביומן! ✨`;
        await bot.telegram.sendMessage(booking.client.telegram_id, clientMsg, { parse_mode: 'Markdown' });

        return res.status(200).json({ success: true });
      } catch (err: any) {
        return res.status(500).json({ error: err.message });
      }
    }

    // --- Cancel Booking ---
    case 'cancel-booking': {
      if (req.method !== 'POST') return res.status(405).send('Method Not Allowed');
      const { bookingId, userId, role } = req.body;
      if (!bookingId || !userId) return res.status(400).send('Missing bookingId or userId');

      // Security Review: we trust the verified caller ID matches the initiator
      // We will enhance checking later via DB RLS or strict back-checks.

      try {
        const status = role === 'master' ? 'cancelled_by_master' : 'cancelled_by_client';
        const { data: booking, error: bErr } = await supabase
          .from('bookings')
          .update({ status })
          .eq('id', bookingId)
          .select('*, master:master_id (telegram_id, business_name, full_name), client:client_id (telegram_id, full_name)')
          .single();

        if (bErr || !booking) return res.status(404).send('Booking not found');

        const bot = new Telegraf(process.env.TELEGRAM_BOT_TOKEN || '');
        const timeStr = new Date(booking.start_time).toLocaleString('he-IL', { hour: '2-digit', minute: '2-digit', day: '2-digit', month: '2-digit' });
        
        if (role === 'master') {
          // Notify Client
          const msg = `😔 **מצטערים, חל שינוי בלוח הזמנים...**\n\nהתור שלך ב-${booking.master.business_name || booking.master.full_name} ב-**${timeStr}** בוטל על ידי המאסטר.\n\nנשמח אם תקבעי תור למועד חדש! ✨`;
          await bot.telegram.sendMessage(booking.client.telegram_id, msg, { parse_mode: 'Markdown' });
        } else {
          // Notify Master
          const msg = `📢 **עדכון: ביטול תור**\n\nהלקוח/ה ${booking.client.full_name} ביטל/ה את התור שנקבע ל-**${timeStr}**.\n\nהמועד הזה התפנה כעת ביומן שלך. 💇‍♀️`;
          await bot.telegram.sendMessage(booking.master.telegram_id, msg, { parse_mode: 'Markdown' });
        }

        return res.status(200).json({ success: true });
      } catch (err: any) {
        return res.status(500).json({ error: err.message });
      }
    }

    // --- Update/Move Booking ---
    case 'update-booking': {
      if (req.method !== 'POST') return res.status(405).send('Method Not Allowed');
      const { bookingId, startTime } = req.body;
      if (!bookingId || !startTime) return res.status(400).send('Missing bookingId or startTime');

      try {
        const { data: oldBooking } = await supabase.from('bookings').select('*, service:service_id(duration_mins)').eq('id', bookingId).single();
        if (!oldBooking) return res.status(404).send('Booking not found');

        const duration = oldBooking.service?.duration_mins || 60;
        const endTime = new Date(new Date(startTime).getTime() + duration * 60 * 1000).toISOString();

        const { data: booking, error: bErr } = await supabase
          .from('bookings')
          .update({ start_time: startTime, end_time: endTime, status: 'pending' })
          .eq('id', bookingId)
          .select('*, master:master_id (telegram_id, business_name, full_name), client:client_id (telegram_id, full_name)')
          .single();

        if (bErr) throw bErr;

        const bot = new Telegraf(process.env.TELEGRAM_BOT_TOKEN || '');
        const timeStr = new Date(startTime).toLocaleString('he-IL', { hour: '2-digit', minute: '2-digit', day: '2-digit', month: '2-digit' });
        
        const masterMsg = `🔄 **התור הוזז!**\n👤 לקוח: ${booking.client.full_name}\n🕓 שעה חדשה: ${timeStr}\n\nהשינוי עודכן ביומן. ✨`;
        const clientMsg = `🔄 **עדכון: התור שלך הוזז**\n📍 עסק: ${booking.master.business_name || booking.master.full_name}\n🕓 שעה חדשה: ${timeStr}\n\nהשינוי מחכה לאישור סופי או מעודכן במערכת. 🙏`;

        await Promise.all([
          bot.telegram.sendMessage(booking.master.telegram_id, masterMsg, { parse_mode: 'Markdown' }),
          bot.telegram.sendMessage(booking.client.telegram_id, clientMsg, { parse_mode: 'Markdown' })
        ]);

        return res.status(200).json({ success: true });
      } catch (err: any) {
        return res.status(500).json({ error: err.message });
      }
    }

    default:
      return res.status(400).json({ error: `Unknown action: ${action}` });
  }
}

import { lazy, Suspense, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import MainLayout from './layouts/MainLayout';
import ErrorBoundary from './components/ErrorBoundary';
import { useAppStore } from './store/useAppStore';
import { supabase } from './lib/supabaseClient';

const Dashboard = lazy(() => import('./pages/Dashboard'));
const Discovery = lazy(() => import('./pages/Discovery'));
const Pricing = lazy(() => import('./pages/Pricing'));
const Settings = lazy(() => import('./pages/Settings'));
const Portfolio = lazy(() => import('./pages/Portfolio'));
const Booking = lazy(() => import('./pages/Booking'));
const ClientDashboard = lazy(() => import('./pages/ClientDashboard'));
const MasterCalendar = lazy(() => import('./pages/MasterCalendar'));

const PageLoader = () => (
  <div className="min-h-screen bg-[#050508] flex items-center justify-center">
    <div className="w-12 h-12 border-4 border-white/10 border-t-yellow-500 rounded-full animate-spin" />
  </div>
);

function App() {
  const userRole = useAppStore((state) => state.user.role);

  useEffect(() => {
    const fetchUser = async () => {
      console.log('APP: Initializing user session...');
      try {
        const tg = (window as any).Telegram?.WebApp;
        if (tg) {
          tg.ready();
          tg.expand();
          console.log('APP: Telegram WebApp context ready');
        }

        const tgUser = tg?.initDataUnsafe?.user;
        
        // If no Telegram user is found, this means we are in local browser env.
        if (!tgUser) {
          console.warn('APP: Local development environment detected. Mocking user session.');
          useAppStore.setState({ 
            user: {
              id: 'local-dev-id-1234',
              name: 'Local Admin',
              role: 'owner', // Defaulting to owner to show UI elements during dev
              subscriptionTier: 'pro',
            }
          });
          return;
        }

        const tgId = tgUser.id;
        console.log(`APP: Fetching profile for TG ID: ${tgId}`);

        const { data, error } = await supabase
          .from('users')
          .select('*')
          .eq('telegram_id', tgId)
          .single();

        if (error) {
          console.warn('APP: Supabase error (expected if DB not seeded):', error.message);
        }

        if (data) {
          console.log('APP: Profile found:', data.business_name || data.full_name);
          useAppStore.setState({ 
            user: {
              id: data.id,
              name: data.full_name,
              role: data.role || 'client',
              subscriptionTier: data.subscription_tier || 'free',
              avatar: data.avatar_url
            }
          });
        } else {
          console.warn('APP: No profile in DB. Auto-registering as client to prevent E2E flow break.');
          const defaultName = tgUser?.first_name ? `${tgUser.first_name} ${tgUser.last_name || ''}`.trim() : `User ${tgId}`;
          
          const { data: newUser, error: insertErr } = await supabase
            .from('users')
            .upsert({ 
              telegram_id: tgId, 
              full_name: defaultName,
              role: 'client' 
            }, { onConflict: 'telegram_id' })
            .select()
            .single();

          if (newUser) {
            useAppStore.setState({ 
              user: {
                id: newUser.id,
                name: newUser.full_name,
                role: 'client',
                subscriptionTier: 'free',
              }
            });
          } else {
            console.error('APP: Auto-registration failed:', insertErr);
            useAppStore.setState(state => ({
              user: { ...state.user, role: 'client' }
            }));
          }
        }
      } catch (err) {
        console.error('APP: Critical initialization error:', err);
      }
    };

    fetchUser();
  }, []);


  return (
    <Router>
      <ErrorBoundary>
        <MainLayout>
          <Suspense fallback={<PageLoader />}>
            <Routes>
              {/* Main Entry Points with conditional logic */}
              <Route path="/" element={userRole === 'client' ? <ClientDashboard /> : <Dashboard />} />
              <Route path="/booking" element={userRole === 'client' ? <Booking /> : <MasterCalendar />} />
              
              {/* Explicit Admin/Unified Routes */}
              <Route path="/dashboard/master" element={<Dashboard />} />
              <Route path="/dashboard/client" element={<ClientDashboard />} />
              <Route path="/calendar" element={userRole === 'client' ? <ClientDashboard /> : <MasterCalendar />} />
              <Route path="/order" element={<Booking />} />

              {/* Shared Routes */}
              <Route path="/discovery" element={<Discovery />} />
              <Route path="/pricing" element={<Pricing />} />
              <Route path="/settings" element={<Settings />} />
              <Route path="/portfolio" element={<Portfolio />} />
            </Routes>
          </Suspense>
        </MainLayout>
      </ErrorBoundary>
    </Router>
  );
}

export default App;

