                className="flex-[2] bg-white text-black py-4 rounded-2xl font-black flex items-center justify-center gap-2 active:scale-95 transition-all text-sm disabled:opacity-50"
              >
                <Navigation size={18} /> {upcoming.status === 'confirmed' ? 'ניווט' : 'ממתין'}
              </button>
              <button 
                onClick={() => navigate(`/order?masterId=${upcoming.master.telegram_id}&rescheduleId=${upcoming.id}`)}
                className="flex-1 bg-zinc-800 text-white py-4 rounded-2xl font-black active:scale-95 transition-all text-sm border border-white/5"
              >
                הזזה
              </button>
              <button 
                onClick={() => handleCancel(upcoming.id)}
                className="px-4 bg-red-500/10 text-red-500 py-4 rounded-2xl font-black active:scale-95 transition-all text-sm border border-red-500/20"
              >
                ביטול
              </button>
            </div>
          </motion.div>
        </section>
      ) : (
        <section className="mb-8 text-center py-20 bg-zinc-900/20 rounded-[40px] border border-dashed border-zinc-800">
            <div className="w-20 h-20 bg-zinc-800 rounded-full mx-auto flex items-center justify-center mb-4">
              <Calendar size={32} className="text-zinc-600" />
            </div>
            <h3 className="text-xl font-bold mb-2">אין לך תורים פעילים</h3>
            <p className="text-zinc-500 text-sm mb-6">רוצה להזמין טיפול חדש בסטייל?</p>
            <button 
              onClick={() => navigate('/discovery')}
              className="gold-gradient px-8 py-4 rounded-full text-black font-black"
            >
              מצא מאסטר קרוב 📍
            </button>
        </section>
      )}

      {others.length > 0 && (
        <section>
          <h3 className="text-xs font-bold uppercase tracking-widest text-zinc-500 mb-4">כל התורים שלי</h3>
          <div className="space-y-3">
            {others.map(booking => (
              <div key={booking.id} className="glass-premium p-4 rounded-2xl flex items-center justify-between border border-white/5">
                <div className="flex items-center gap-4">
                  <div className="w-12 h-12 bg-white/5 rounded-xl flex items-center justify-center text-zinc-500">
                    <Clock size={20} />
                  </div>
                  <div>
                    <div className="font-bold text-sm">{booking.master.business_name || booking.master.full_name}</div>
                    <div className="text-xs text-zinc-500">
                      {new Date(booking.start_time).toLocaleDateString('he-IL', { day: 'numeric', month: 'short' })} • {new Date(booking.start_time).toLocaleTimeString('he-IL', { hour: '2-digit', minute: '2-digit' })}
                    </div>
                  </div>
                </div>
                <div className={`text-[10px] font-black uppercase px-2 py-1 rounded ${booking.status === 'confirmed' ? 'bg-green-500/10 text-green-500' : 'bg-zinc-800 text-zinc-400'}`}>
                  {booking.status === 'confirmed' ? 'מאושר' : 'עבר'}
                </div>
              </div>
            ))}
          </div>
        </section>
      )}
    </div>
  );
};

export default ClientDashboard;

import { useState, useEffect, useRef } from 'react';
import * as Lucide from 'lucide-react';

// Обход ошибок типизации в текущем окружении tsc
const { 
  Camera, 
  Sparkles, 
  Bookmark, 
  CheckCircle, 
  LoaderCircle 
} = Lucide as any;
import { useTelegram } from '../hooks/useTelegram';
import { supabase } from '../lib/supabaseClient';
import { useAppStore } from '../store/useAppStore';

const Dashboard = () => {
  const { tg, haptic, setMainButton, hideMainButton, user } = useTelegram();
  const safeUser = user || { first_name: 'Beauty Master', id: 'unknown' };

  const [activeSocial, setActiveSocial] = useState('Instagram');
  const [businessName] = useState(safeUser.first_name || 'Beauty Master');
  const [imagePreview, setImagePreview] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [saveSuccess, setSaveSuccess] = useState(false);
  const [generatedResults, setGeneratedResults] = useState<any>(null);
  const [isLoaded, setIsLoaded] = useState(false);

  // New State for Real Data
  const [stats, setStats] = useState({ views: 0, appointments: 0 });
  const [upcomingBookings, setUpcomingBookings] = useState<any[]>([]);
  const [pendingBookings, setPendingBookings] = useState<any[]>([]);
  const [isLoadingData, setIsLoadingData] = useState(true);

  const appUser = useAppStore(state => state.user);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (tg) {
      tg.ready();
      tg.expand();
    }
    const timer = setTimeout(() => setIsLoaded(true), 100);
    return () => clearTimeout(timer);
  }, [tg]);

  useEffect(() => {
    const fetchData = async () => {
      if (!appUser.id) return;
      setIsLoadingData(true);
      try {
        // 1. Fetch Stats (Profile Views)
        const { count: viewsCount } = await supabase
          .from('analytics_events')
          .select('*', { count: 'exact', head: true })
          .eq('master_id', appUser.id)
          .eq('event_type', 'profile_view');

        // 2. Fetch Appointments count (Last 7 days)
        const weekAgo = new Date();
        weekAgo.setDate(weekAgo.getDate() - 7);
        const { count: bookCount } = await supabase
          .from('bookings')
          .select('*', { count: 'exact', head: true })
          .eq('master_id', appUser.id)
          .gte('created_at', weekAgo.toISOString());

        setStats({ views: viewsCount || 0, appointments: bookCount || 0 });

        // 3. Fetch Bookings
        const { data: allBookings } = await supabase
          .from('bookings')
          .select('id, start_time, status, client:client_id (full_name)')
          .eq('master_id', appUser.id)
          .gte('start_time', new Date().toISOString())
          .order('start_time', { ascending: true });

        const pending = allBookings?.filter((b: any) => b.status === 'pending') || [];
        const upcoming = allBookings?.filter((b: any) => b.status === 'confirmed').slice(0, 5) || [];

        setPendingBookings(pending);
        setUpcomingBookings(upcoming);
      } catch (err) {
        console.error('DASHBOARD: Error fetching data:', err);
      } finally {
        setIsLoadingData(false);
      }
    };

    fetchData();
  }, [appUser.id]);

  useEffect(() => {
    const currentText = generatedResults ? (generatedResults[activeSocial.toLowerCase()] || generatedResults.instagram) : null;
    if (tg && currentText && !isGenerating) {
      setMainButton('פרסום עכשיו ✨', () => {
        haptic('heavy');
        tg.sendData(JSON.stringify({ action: 'publish', text: currentText, social: activeSocial, image: imagePreview }));
        alert('הפוסט נשלח לבוט לפרסום!');
      });
    } else {
      hideMainButton();
    }
  }, [tg, haptic, setMainButton, hideMainButton, generatedResults, isGenerating, activeSocial, imagePreview]);

  const socialNetworks = [
    { id: 'Instagram', name: 'Instagram', ratio: '9/16' },
    { id: 'Facebook', name: 'Facebook', ratio: '1.91/1' },
    { id: 'Telegram', name: 'Telegram', ratio: '1/1' },
    { id: 'WhatsApp', name: 'WhatsApp', ratio: '1/1' }
  ];

  const handleUploadClick = () => {
    haptic('medium');
    fileInputRef.current?.click();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImagePreview(reader.result as string);
        setGeneratedResults(null);
        haptic('light');
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGenerate = async () => {
    if (!imagePreview) return;
    setIsGenerating(true);
    haptic('heavy');
    try {
      const baseUrl = window.location.origin; 
      const response = await fetch(`${baseUrl}/api/enhance`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ image: imagePreview, format: activeSocial, businessName }),
      });
      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(`AI Connection Error: ${errorData.error || 'Unknown'}\nDetails: ${JSON.stringify(errorData.details)}\nModel: ${errorData.model}`);
      }
      const data = await response.json();
      setImagePreview(data.enhancedImage);
      setGeneratedResults({ instagram: data.post, whatsapp: data.post, facebook: data.post, telegram: data.post, short_overlay: data.service });
      haptic('medium');
    } catch (error: any) {
      console.error(error);
      alert(`שגיאה בחיבור ל-AI:\n${error.message}`);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleSaveToGallery = async () => {
    if (!imagePreview || !user?.id) return;
    setIsSaving(true);
    haptic('medium');
    try {
      const { error } = await supabase
        .from('portfolio')
        .insert([{ 
          user_id: user.id.toString(), 
          image_url: imagePreview,
          type: 'ai_creation',
          metadata: { format: activeSocial, businessName }
        }]);

      if (error) throw error;
      setSaveSuccess(true);
      haptic('success');
      setTimeout(() => setSaveSuccess(false), 3000);
    } catch (err) {
      console.error('Error saving to gallery:', err);
      alert('שגיאה בשמירה לגלריה.');
    } finally {
      setIsSaving(false);
    }
